function scorriChatInBasso(){var position=$(".chat_message_bubble_user").last().position();$('html, body').animate({scrollTop:position.top},500)}
function aggiornaChat(){$.ajaxQueue({url:baseUrl+"/virtual-assistant/messages/",cache:!1,async:!0,dataType:"html",success:function(content){$(".chat_messages").html(content);setTimeout(function(){scorriChatInBasso()},100)}})}
$(document).ready(function(){scorriChatInBasso();$("body").on("keypress",".request_message",function(e){if(e.which==13){e.preventDefault();$(".send_request_to_va").trigger("click")}});$("body").on("click",".send_request_to_va",function(e){e.preventDefault();var bottone=$(this);var loader=bottone.find(".send_request_to_va_loader");var testo=bottone.find(".send_request_to_va_text");var messaggio=$(".request_message").val();if(!messaggio.length||bottone.prop("disabled"))
return;bottone.prop("disabled",!0);testo.addClass("uk-hidden");loader.removeClass("uk-hidden");$.ajaxQueue({url:baseUrl+"/virtual-assistant/request/",async:!0,cache:!1,type:"POST",data:{messaggio:messaggio},dataType:"html",success:function(content){$(".request_message").val("");aggiornaChat()},complete:function(){bottone.prop("disabled",!1);testo.removeClass("uk-hidden");loader.addClass("uk-hidden")}})})})